import React, { useState } from 'react';
import './DashboardPage.css';
import UploadDropzone from '../components/ui/UploadDropzone';
import TransferProgress from '../components/ui/TransferProgress';

const DashboardPage = ({ 
  stats, 
  peersCount, 
  groups, 
  setView, 
  selectGroup, 
  fetchStats,
  activeTransfersList = [],
  webrtcPeers = [],
  webrtc,
  notify
}) => {
  const [selectedPeer, setSelectedPeer] = useState("");
  const [tags, setTags] = useState("");
  const [loading, setLoading] = useState(false);

  const handleUpload = (e, file) => {
    if (!selectedPeer) {
      if (notify) notify("Please select a peer to send to first.", "error");
      return;
    }
    if (!webrtc) {
      if (notify) notify("WebRTC not connected. Try refreshing.", "error");
      return;
    }
    const peerObj = webrtcPeers.find((p) => p.socketId === selectedPeer);
    if (!peerObj) {
      if (notify) notify("Peer is offline or invalid.", "error");
      return;
    }
    if (notify) notify(`Initiating direct P2P transfer to ${peerObj.peerName}`);
    webrtc.sendFile(selectedPeer, file);
    setView("transfers"); 
  };

  // Mock recent activity since it's not in the state yet
  const recentActivity = [
    { id: 1, text: "Proposal.pdf shared to Design Team", time: "2 mins ago", status: "Completed"},
    { id: 2, text: "Report.docx received from Sarah", time: "1 hour ago", status: "Downloaded"},
    { id: 3, text: "Presentation.pptx shared to Project Alpha", time: "3 hours ago", status: "Completed"},
    { id: 4, text: "Photo.jpg received from Mike", time: "8 hours ago", status: "Downloaded"}
  ];

  return (
    <div className="dashboard-page fade-in">

      <div className="dashboard-main">
        <div className="page-header">
          <h1 className="page-title">Good evening 👋</h1>
          <p className="muted">Here's what's happening with your P2P network today.</p>
        </div>

        <div className="stats-grid">
          <div className="stat-box card">
            <div className="stat-icon">👥</div>
            <div className="stat-info">
              <h3 className="stat-title">Groups</h3>
              <p className="stat-number">{stats.groupCount || 0}</p>
              <small className="stat-label">Active groups</small>
            </div>
          </div>

          <div className="stat-box card">
            <div className="stat-icon">📄</div>
            <div className="stat-info">
              <h3 className="stat-title">Files Shared</h3>
              <p className="stat-number">{stats.fileCount || 0}</p>
              <small className="stat-label">Files uploaded</small>
            </div>
          </div>

          <div className="stat-box card">
            <div className="stat-icon">💻</div>
            <div className="stat-info">
              <h3 className="stat-title">Peers Online</h3>
              <p className="stat-number">{peersCount}</p>
              <small className="stat-label">Connected</small>
            </div>
          </div>

          <div className="stat-box card">
            <div className="stat-icon">💽</div>
            <div className="stat-info">
              <h3 className="stat-title">Storage Used</h3>
              <p className="stat-number">2.4 GB</p>
              <small className="stat-label">Local usage</small>
            </div>
          </div>
        </div>

        <div className="quick-actions-card">
          <h3>Quick Actions</h3>
          <div className="quick-actions-grid">
            <button className="quick-action-btn card" onClick={() => setView("upload")}>
              <div className="action-icon-wrapper">📤</div>
              <div className="action-text">
                <strong>Upload Files</strong>
                <small>Send to peers</small>
              </div>
            </button>

            <button className="quick-action-btn card" onClick={() => setView("creategroup")}>
              <div className="action-icon-wrapper">➕</div>
              <div className="action-text">
                <strong>Create Group</strong>
                <small>New peer group</small>
              </div>
            </button>

            <button className="quick-action-btn card" onClick={() => setView("peers")}>
              <div className="action-icon-wrapper">🌐</div>
              <div className="action-text">
                <strong>View Peers</strong>
                <small>See online peers</small>
              </div>
            </button>

            <button className="quick-action-btn card" onClick={() => setView("transfers")}>
              <div className="action-icon-wrapper">🔄</div>
              <div className="action-text">
                <strong>Transfer History</strong>
                <small>Recent activity</small>
              </div>
            </button>
          </div>
        </div>

        <div className="recent-activity-section card">
          <h3 style={{marginTop: 0, marginBottom: '1.5rem', color: 'var(--text-primary)', fontSize: '1.25rem'}}>Recent Activity</h3>
          <div className="activity-list">
            {recentActivity.map(item => (
              <div key={item.id} className="activity-item">
                <div className="activity-icon-small">📄</div>
                <div className="activity-details">
                  <p className="activity-text">{item.text}</p>
                  <small className="activity-time">{item.time}</small>
                </div>
                <span className={`activity-status ${item.status.toLowerCase()}`}>{item.status}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      <div className="dashboard-rightbar">

        <div className="peers-panel card">
          <div className="panel-header">
            <h3>🟢 Peers Online</h3>
            <span className="badge">{peersCount} connected</span>
          </div>
          <div className="peers-list" style={{ marginTop: '1rem'}}>
            {webrtcPeers.length === 0 ? (
              <p className="muted" style={{fontSize: '0.85rem'}}>No active WebRTC peers.</p>
            ) : (
              webrtcPeers.slice(0, 4).map(p => (
                <div key={p.socketId} className="peer-item" style={{display: 'flex', alignItems: 'center', gap: '0.75rem', marginBottom: '1rem', padding: '0.5rem', borderRadius: 'var(--radius-md)', background: 'var(--bg-surface-hover)'}}>
                   <div className="peer-avatar" style={{width: '36px', height: '36px', borderRadius: '50%', background: 'var(--color-primary-100)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontWeight: 'bold', color: 'var(--color-primary-700)'}}>{p.peerName.charAt(0).toUpperCase()}</div>
                   <div className="peer-info" style={{flex: 1}}>
                     <p className="peer-name" style={{margin: '0 0 2px 0', fontSize: '0.9rem', fontWeight: 600, color: 'var(--text-primary)'}}>{p.peerName}</p>
                     <p className="peer-status" style={{margin: 0, fontSize: '0.75rem', color: 'var(--text-muted)', display: 'flex', alignItems: 'center', gap: '4px'}}>
                        <span className="live-dot" style={{width: '6px', height: '6px', borderRadius: '50%', background: 'var(--color-success)', display: 'inline-block'}}></span> Online - Sharing enabled
                     </p>
                   </div>
                   <button className="connect-btn" style={{padding: '0.25rem 0.75rem', fontSize: '0.75rem', background: 'var(--bg-surface)', border: '1px solid var(--border-color)', borderRadius: 'var(--radius-full)', color: 'var(--text-primary)'}} onClick={() => {
                        setSelectedPeer(p.socketId);
                   }}>Connect</button>
                </div>
              ))
            )}
            <button className="view-all-btn" style={{width: '100%', padding: '0.75rem', background: 'var(--color-primary-600)', color: 'white', borderRadius: 'var(--radius-md)', border: 'none', fontWeight: 500, marginTop: '0.5rem'}} onClick={() => setView("peers")}>View All Peers</button>
          </div>
        </div>

        <div className="upload-panel card">
          <h3 style={{marginTop: 0, marginBottom: '0.25rem', color: 'var(--text-primary)', fontSize: '1.1rem'}}>Upload Files to Peer</h3>
          <p className="muted" style={{fontSize: '0.8rem', marginBottom: '1.25rem', color: 'var(--text-muted)'}}>Secure P2P file sharing</p>

          <select
             value={selectedPeer}
             onChange={(e) => setSelectedPeer(e.target.value)}
             className="peer-select-dropdown"
             style={{width: '100%', padding: '0.75rem', borderRadius: 'var(--radius-md)', border: '1px solid var(--border-color)', background: 'var(--bg-main)', color: 'var(--text-primary)', marginBottom: '1rem', outline: 'none'}}
          >
             <option value="" disabled>-- Select recipient --</option>
             {webrtcPeers.map(p => (
                <option key={p.socketId} value={p.socketId}>
                   {p.peerName}
                </option>
             ))}
          </select>

          <UploadDropzone
              onUpload={handleUpload}
              tags={tags}
              setTags={setTags}
              loading={loading}
          />
        </div>

        {activeTransfersList.length > 0 && (
          <div className="transfers-panel card">
            <h3 style={{marginTop: 0, marginBottom: '1rem', color: 'var(--text-primary)', fontSize: '1.1rem'}}>Active Transfers</h3>
            <TransferProgress activeTransfers={activeTransfersList} embedded={true} />
          </div>
        )}
      </div>

    </div>
  );
};

export default DashboardPage;
